   185→/* ====  Implementation  ===================================================== */
   186→#ifdef LEXILEARN_DRIFT_DETECTOR_IMPLEMENTATION
   187→/*  Internal helper macros  */
   188→#define LEXI_MIN(a,b) ((a) < (b) ? (a) : (b))
   189→#define LEXI_MAX(a,b) ((a) > (b) ? (a) : (b))
   190→
   191→struct lexi_drift_detector
   192→{
   193→    lexi_drift_cfg_t    cfg;
   194→    size_t              sample_count;                  /* # observations      */
   195→    double              reference[LEXI_MAX_BINS];      /* Training dist.      */
   196→    double              rolling_actual[LEXI_MAX_BINS]; /* Sliding window dist */
   197→    double              last_score;
   198→    bool                drifting;
   199→
   200→    /* Observer Pattern */
   201→    lexi_drift_listener_t listeners[LEXI_MAX_LISTENERS];
   202→    void*                 listener_ctx[LEXI_MAX_LISTENERS];
   203→    size_t                listener_cnt;
   204→
   205→    /* Thread-safety */
   206→    pthread_mutex_t      mtx;
   207→};
   208→
   209→/* ====  Utility: Safe allocation wrapper  ================================== */
   210→static inline void* lexi_xcalloc(size_t n, size_t sz)
   211→{
   212→    void* p = calloc(n, sz);
   213→    return p;
   214→}
   215→
   216→/* ====  Metric Implementations  =========================================== */
   217→static double
   218→lexi_compute_psi(const double* ref, const double* act, size_t k)
   219→{
   220→    double psi = 0.0;
   221→    for (size_t i = 0; i < k; ++i)
   222→    {
   223→        const double e = ref[i] <= 0.0 ? 1e-12 : ref[i];
   224→        const double a = act[i] <= 0.0 ? 1e-12 : act[i];
   225→        psi += (a - e) * log(a / e);
   226→    }
   227→    return psi;
   228→}
   229→
   230→static double
   231→lexi_compute_kl(const double* ref, const double* act, size_t k)
   232→{
   233→    double kl = 0.0;
   234→    for (size_t i = 0; i < k; ++i)
   235→    {
   236→        double a = act[i] <= 0.0 ? 1e-12 : act[i];
   237→        double r = ref[i] <= 0.0 ? 1e-12 : ref[i];
   238→        kl += a * log(a / r);
   239→    }
   240→    return kl;
   241→}
   242→
   243→static double
   244→lexi_compute_wasserstein(const double* ref, const double* act, size_t k)
   245→{
   246→    /* 1-dimensional 1-Wasserstein distance for histograms */
   247→    double cum_ref = 0.0, cum_act = 0.0, wass = 0.0;
   248→    for (size_t i = 0; i < k; ++i)
   249→    {
   250→        cum_ref += ref[i];
   251→        cum_act += act[i];
   252→        wass += fabs(cum_ref - cum_act);
   253→    }
   254→    return wass;
   255→}
   256→
   257→/* ====  Private helper: notify listeners  ================================== */
   258→static void
   259→lexi_notify(const lexi_drift_detector_t* det)
   260→{
   261→    lexi_drift_event_t evt;
   262→    strncpy(evt.model_id, det->cfg.model_id, LEXI_MODEL_ID_LEN);
   263→    evt.score     = det->last_score;
   264→    evt.threshold = det->cfg.threshold;
   265→    evt.timestamp = time(NULL);
   266→
   267→    for (size_t i = 0; i < det->listener_cnt; ++i)
   268→    {
   269→        det->listeners[i](&evt, det->listener_ctx[i]);
   270→    }
   271→}
   272→
   273→/* ====  Public API: Create  ================================================= */
   274→lexi_drift_detector_t*
   275→lexi_drift_create(const lexi_drift_cfg_t* cfg, lexi_error_t* err)
   276→{
   277→    if (!cfg || cfg->num_bins == 0 || cfg->num_bins > LEXI_MAX_BINS)
   278→    {
   279→        if (err) *err = LEXI_EINVAL;
   280→        return NULL;
   281→    }
   282→
   283→    lexi_drift_detector_t* det = (lexi_drift_detector_t*)lexi_xcalloc(1, sizeof(*det));
   284→    if (!det)
   285→    {
   286→        if (err) *err = LEXI_ENOMEM;
   287→        return NULL;
   288→    }
   289→
   290→    det->cfg = *cfg;
   291→    /* Initialize reference distribution to uniform until calibrated */
   292→    for (size_t i = 0; i < cfg->num_bins; ++i)
   293→        det->reference[i] = 1.0 / (double)cfg->num_bins;
   294→
   295→    if (pthread_mutex_init(&det->mtx, NULL) != 0)
   296→    {
   297→        free(det);
   298→        if (err) *err = LEXI_ETHREAD;
   299→        return NULL;
   300→    }
   301→    if (err) *err = LEXI_OK;
   302→    return det;
   303→}
   304→
   305→/* ====  Public API: Destroy  ============================================== */
   306→void
   307→lexi_drift_destroy(lexi_drift_detector_t* det)
   308→{
   309→    if (!det) return;
   310→    pthread_mutex_destroy(&det->mtx);
   311→    free(det);
   312→}
   313→
   314→/* ====  Public API: Update  =============================================== */
   315→void
   316→lexi_drift_update(lexi_drift_detector_t* det,
   317→                  const double*          probs,
   318→                  lexi_error_t*          err)
   319→{
   320→    if (!det || !probs)
   321→    {
   322→        if (err) *err = LEXI_EINVAL;
   323→        return;
   324→    }
   325→
   326→    pthread_mutex_lock(&det->mtx);
   327→    const size_t k = det->cfg.num_bins;
   328→
   329→    /* Exponential moving average for rolling distribution */
   330→    const double alpha = 1.0 / (double)LEXI_MAX(1, det->cfg.window);
   331→    for (size_t i = 0; i < k; ++i)
   332→    {
   333→        double p = probs[i];
   334→        if (p < 0.0)
   335→        {
   336→            pthread_mutex_unlock(&det->mtx);
   337→            if (err) *err = LEXI_EINVAL;
   338→            return;
   339→        }
   340→        det->rolling_actual[i] =
   341→            (1.0 - alpha) * det->rolling_actual[i] + alpha * p;
   342→    }
   343→
   344→    /* Compute drift metric */
   345→    switch (det->cfg.metric)
   346→    {
   347→        case LEXI_DRIFT_PSI:
   348→            det->last_score = lexi_compute_psi(det->reference,
   349→                                               det->rolling_actual, k);
   350→            break;
   351→        case LEXI_DRIFT_KL:
   352→            det->last_score = lexi_compute_kl(det->reference,
   353→                                              det->rolling_actual, k);
   354→            break;
   355→        case LEXI_DRIFT_WASSER:
   356→            det->last_score = lexi_compute_wasserstein(det->reference,
   357→                                                       det->rolling_actual, k);
   358→            break;
   359→        default:
   360→            det->last_score = 0.0;
   361→            break;
   362→    }
   363→
   364→    bool drift_now = det->last_score >= det->cfg.threshold;
   365→    if (drift_now && !det->drifting)
   366→    {
   367→        det->drifting = true;
   368→        lexi_notify(det); /* fire Observer callbacks */
   369→    }
   370→    else if (!drift_now && det->drifting)
   371→    {
   372→        det->drifting = false; /* reset flag */
   373→    }
   374→
   375→    det->sample_count++;
   376→    pthread_mutex_unlock(&det->mtx);
   377→
   378→    if (err) *err = LEXI_OK;
   379→}
   380→
   381→/* ====  Public API: is_drifting  ========================================== */
   382→bool
   383→lexi_drift_is_drifting(const lexi_drift_detector_t* det, double* out_score)
   384→{
   385→    if (!det) return false;
   386→    if (out_score) *out_score = det->last_score;
   387→    return det->drifting;
   388→}
   389→
   390→/* ====  Public API: add/remove listener  =================================== */
   391→lexi_error_t
   392→lexi_drift_add_listener(lexi_drift_detector_t* det,
   393→                        lexi_drift_listener_t  fn,
   394→                        void*                  ctx)
   395→{
   396→    if (!det || !fn) return LEXI_EINVAL;
   397→    pthread_mutex_lock(&det->mtx);
   398→
