1→/*
     2→ *  drift_detector.c
     3→ *  LexiLearn Orchestrator – Controller / Monitoring Component
     4→ *
     5→ *  Description:
     6→ *      Implements real-time model-drift detection using a Page-Hinkley Test for
     7→ *      each registered model instance.  The detector is designed as an Observer
     8→ *      that publishes drift events back to the Controller’s event-bus so that
     9→ *      automated retraining jobs can be triggered without human intervention.
    10→ *
    11→ *  Design highlights:
    12→ *      • One drift state per model, stored in an in-memory hash map (uthash).
    13→ *      • Thread-safe; synchronizes access with a POSIX mutex.
    14→ *      • Supports multiple user-supplied callbacks (observers) to decouple the
    15→ *        detector from concrete retraining, alerting, or logging logic.
    16→ *
    17→ *  Compile flags:
    18→ *      gcc -Wall -Wextra -pedantic -std=c11 -pthread -o drift_detector.o -c drift_detector.c
    19→ *
    20→ *  External dependencies:
    21→ *      • uthash.h         – single-header hash-table implementation (MIT License)
    22→ *      • pthread (glibc)  – for synchronization
    23→ */
    24→
    25→#include <stdio.h>
    26→#include <stdlib.h>
    27→#include <string.h>
    28→#include <pthread.h>
    29→#include <errno.h>
    30→
    31→#include "uthash.h"            /* Hash-table for mapping model_id → drift state */
    32→#include "drift_detector.h"    /* Public header for this implementation          */
    33→
    34→
    35→/* ============================================================================
    36→ *  Type definitions
    37→ * ========================================================================== */
    38→
    39→/* Internal representation of the Page-Hinkley drift state for a model. */
    40→typedef struct {
    41→    char            model_id[64];      /* unique identifier (hash-key)          */
    42→    double          x_mean;            /* running mean of the monitored metric  */
    43→    double          cumulative_sum;    /* Page-Hinkley cumulative difference    */
    44→    double          min_cumulative_sum;/* Minimum cumulative sum seen so far    */
    45→    size_t          sample_count;      /* N                                    */
    46→    double          delta;             /* Small magnitude to ignore             */
    47→    double          lambda;            /* Drift threshold                       */
    48→    UT_hash_handle  hh;                /* uthash handle                         */
    49→} model_drift_state_t;
    50→
    51→
    52→/* Linked list node for callback registry. */
    53→typedef struct callback_node {
    54→    drift_callback_t        fn;
    55→    void                   *user_data;
    56→    struct callback_node   *next;
    57→} callback_node_t;
    58→
    59→
    60→/* ============================================================================
    61→ *  Module-level globals   (protected by g_lock)
    62→ * ========================================================================== */
    63→
    64→static model_drift_state_t *g_model_states = NULL;  /* uthash head              */
    65→static callback_node_t     *g_callbacks    = NULL;  /* observer registry list   */
    66→static pthread_mutex_t      g_lock         = PTHREAD_MUTEX_INITIALIZER;
    67→static int                  g_initialized  = 0;
    68→
    69→
    70→/* ============================================================================
    71→ *  Helper / Internal functions
    72→ * ========================================================================== */
    73→
    74→/* Publish a drift event to all registered observers. */
    75→static void
    76→publish_drift_event(const char *model_id, const char *reason)
    77→{
    78→    callback_node_t *node = g_callbacks;
    79→
    80→    while (node) {
    81→        node->fn(model_id, reason, node->user_data);
    82→        node = node->next;
    83→    }
    84→}
    85→
    86→
    87→/* Ensure the library has been initialized once. */
    88→static int
    89→ensure_initialized(void)
    90→{
    91→    if (__builtin_expect(g_initialized, 1))
    92→        return 0;
    93→
    94→    int rc = pthread_mutex_lock(&g_lock);
    95→    if (rc != 0) return rc;
    96→
    97→    if (!g_initialized) {
    98→        /* Potential future initialization: connect to central event bus, etc. */
    99→        g_initialized = 1;
   100→    }
   101→
   102→    return pthread_mutex_unlock(&g_lock);
   103→}
   104→
   105→
   106→/* ============================================================================
   107→ *  Public API – see header for documentation
   108→ * ========================================================================== */
   109→
   110→int
   111→drift_detector_register_model(const char *model_id,
   112→                              double       delta,
   113→                              double       lambda)
   114→{
   115→    if (!model_id || delta <= 0.0 || lambda <= 0.0)
   116→        return EINVAL;
   117→
   118→    int rc = ensure_initialized();
   119→    if (rc != 0) return rc;
   120→
   121→    rc = pthread_mutex_lock(&g_lock);
   122→    if (rc != 0) return rc;
   123→
   124→    /* Check if model already exists. */
   125→    model_drift_state_t *state = NULL;
   126→    HASH_FIND_STR(g_model_states, model_id, state);
   127→    if (state) {
   128→        pthread_mutex_unlock(&g_lock);
   129→        return EEXIST;
   130→    }
   131→
   132→    /* Create new drift state. */
   133→    state = calloc(1, sizeof(model_drift_state_t));
   134→    if (!state) {
   135→        pthread_mutex_unlock(&g_lock);
   136→        return ENOMEM;
   137→    }
   138→
   139→    strncpy(state->model_id, model_id, sizeof(state->model_id) - 1);
   140→    state->delta                = delta;
   141→    state->lambda               = lambda;
   142→    state->x_mean               = 0.0;
   143→    state->cumulative_sum       = 0.0;
   144→    state->min_cumulative_sum   = 0.0;
   145→    state->sample_count         = 0;
   146→
   147→    HASH_ADD_STR(g_model_states, model_id, state);
   148→
   149→    pthread_mutex_unlock(&g_lock);
   150→    return 0;
   151→}
   152→
   153→
   154→int
   155→drift_detector_unregister_model(const char *model_id)
   156→{
   157→    if (!model_id) return EINVAL;
   158→
   159→    int rc = pthread_mutex_lock(&g_lock);
   160→    if (rc != 0) return rc;
   161→
   162→    model_drift_state_t *state = NULL;
   163→    HASH_FIND_STR(g_model_states, model_id, state);
   164→    if (!state) {
   165→        pthread_mutex_unlock(&g_lock);
   166→        return ENOENT;
   167→    }
   168→
   169→    HASH_DEL(g_model_states, state);
   170→    free(state);
   171→
   172→    pthread_mutex_unlock(&g_lock);
   173→    return 0;
   174→}
   175→
   176→
   177→int
   178→drift_detector_update_metric(const char *model_id, double metric_value)
   179→{
   180→    if (!model_id) return EINVAL;
   181→
   182→    int rc = ensure_initialized();
   183→    if (rc != 0) return rc;
   184→
   185→    rc = pthread_mutex_lock(&g_lock);
   186→    if (rc != 0) return rc;
   187→
   188→    model_drift_state_t *state = NULL;
   189→    HASH_FIND_STR(g_model_states, model_id, state);
   190→    if (!state) {
   191→        pthread_mutex_unlock(&g_lock);
   192→        return ENOENT;
   193→    }
   194→
   195→    /* Update running mean incrementally. */
   196→    state->sample_count += 1;
   197→    double prev_mean = state->x_mean;
   198→    state->x_mean += (metric_value - prev_mean) / (double)state->sample_count;
   199→
   200→    /* Page-Hinkley test g_t = Σ (x_t – mean_t – δ) */
   201→    state->cumulative_sum += (metric_value - state->x_mean - state->delta);
   202→    if (state->cumulative_sum < state->min_cumulative_sum)
   203→        state->min_cumulative_sum = state->cumulative_sum;
   204→
   205→    double ph_statistic = state->cumulative_sum - state->min_cumulative_sum;
   206→
   207→    /* Drift detected? */
   208→    if (ph_statistic > state->lambda) {
   209→        char reason[128];
   210→        snprintf(reason, sizeof(reason),
