   199→static rt_model_entry_t *_rt_find_entry(const char *model_id)
   200→{
   201→    for (size_t i = 0; i < RT_MAX_MODELS; ++i)
   202→    {
   203→        if (_rt_state.entries[i].in_use &&
   204→            strncmp(_rt_state.entries[i].model_id, model_id, RT_MODEL_ID_MAX) == 0)
