   212→/* Compute average of N most recent samples from ring buffer */
   213→static double _rt_avg_last_n(const rt_model_entry_t *ent, size_t n)
   214→{
   215→    if (ent->count == 0) { return 0.0; }
   216→    n = RT_MIN(n, ent->count);
   217→    double sum = 0.0;
   218→    for (size_t i = 0; i < n; ++i)
   219→    {
   220→        size_t idx = (ent->head + RT_MAX_SAMPLES - 1 - i) % RT_MAX_SAMPLES;
   221→        sum += ent->samples[idx].value;
   222→    }
   223→    return sum / (double) n;
   224→}
