   227→static double _rt_avg_first_n(const rt_model_entry_t *ent, size_t n)
   228→{
   229→    if (ent->count == 0) { return 0.0; }
   230→    n = RT_MIN(n, ent->count);
   231→    double sum = 0.0;
   232→    size_t start = (ent->head + RT_MAX_SAMPLES - ent->count) % RT_MAX_SAMPLES;
   233→    for (size_t i = 0; i < n; ++i)
   234→    {
   235→        size_t idx = (start + i) % RT_MAX_SAMPLES;
   236→        sum += ent->samples[idx].value;
   237→    }
   238→    return sum / (double) n;
