   256→void rt_trigger_shutdown(void)
   257→{
   258→    pthread_mutex_lock(&_rt_state.mtx);
   259→    memset(_rt_state.entries, 0, sizeof(_rt_state.entries));
   260→    _rt_state.callback    = NULL;
   261→    _rt_state.initialized = false;
   262→    pthread_mutex_unlock(&_rt_state.mtx);
   263→}
