   265→rt_status_t rt_register_model(const char *model_id,
   266→                              rt_metric_t metric,
   267→                              double drift_threshold_pct)
   268→{
   269→    if (!model_id || drift_threshold_pct <= 0.0) { return RT_ERR_BAD_PARAM; }
   270→
   271→    rt_status_t status = RT_ERR_FULL;
   272→    pthread_mutex_lock(&_rt_state.mtx);
   273→
   274→    /* duplicate? */
   275→    if (_rt_find_entry(model_id) != NULL)
   276→    {
   277→        status = RT_ERR_ALREADY_EXISTS;
   278→        goto out;
   279→    }
   280→
   281→    /* locate free slot */
   282→    for (size_t i = 0; i < RT_MAX_MODELS; ++i)
   283→    {
   284→        if (!_rt_state.entries[i].in_use)
   285→        {
   286→            rt_model_entry_t *ent = &_rt_state.entries[i];
   287→            memset(ent, 0, sizeof(*ent));
   288→            ent->in_use              = true;
   289→            ent->metric_type         = metric;
   290→            ent->drift_threshold_pct = drift_threshold_pct;
   291→            strncpy(ent->model_id, model_id, RT_MODEL_ID_MAX - 1);
   292→            status = RT_OK;
   293→            goto out;
   294→        }
   295→    }
   296→
   297→out:
   298→    pthread_mutex_unlock(&_rt_state.mtx);
   299→    return status;
   300→}
   301→
   302→rt_status_t rt_unregister_model(const char *model_id)
   303→{
   304→    if (!model_id) { return RT_ERR_BAD_PARAM; }
   305→
   306→    pthread_mutex_lock(&_rt_state.mtx);
   307→    rt_model_entry_t *ent = _rt_find_entry(model_id);
   308→    if (ent)
   309→    {
   310→        memset(ent, 0, sizeof(*ent));
   311→        pthread_mutex_unlock(&_rt_state.mtx);
   312→        return RT_OK;
   313→    }
   314→    pthread_mutex_unlock(&_rt_state.mtx);
   315→    return RT_ERR_NOT_FOUND;
   316→}
   317→
   318→rt_status_t rt_record_metric(const char *model_id,
   319→                             double      value,
   320→                             uint64_t    timestamp_ms)
   321→{
   322→    if (!model_id) { return RT_ERR_BAD_PARAM; }
   323→    if (timestamp_ms == 0) { timestamp_ms = _rt_now_ms(); }
   324→
   325→    pthread_mutex_lock(&_rt_state.mtx);
   326→    rt_model_entry_t *ent = _rt_find_entry(model_id);
   327→    if (!ent)
   328→    {
   329→        pthread_mutex_unlock(&_rt_state.mtx);
   330→        return RT_ERR_NOT_FOUND;
   331→    }
   332→
   333→    /* insert into ring buffer */
   334→    ent->samples[ent->head].value  = value;
   335→    ent->samples[ent->head].ts_ms  = timestamp_ms;
   336→    ent->head   = (ent->head + 1) % RT_MAX_SAMPLES;
   337→    ent->count  = RT_MIN(ent->count + 1, RT_MAX_SAMPLES);
   338→
   339→    pthread_mutex_unlock(&_rt_state.mtx);
   340→    return RT_OK;
   341→}
   342→
   343→/* Determine drift for a single entry (lock must be held) */
   344→static bool _rt_drift_detected(rt_model_entry_t *ent)
   345→{
   346→    if (ent->count < RT_BASELINE_WINDOW * 2) { return false; }
   347→
   348→    double baseline = _rt_avg_first_n(ent, RT_BASELINE_WINDOW);
   349→    double current  = _rt_avg_last_n(ent,  RT_BASELINE_WINDOW);
   350→
   351→    if (baseline == 0.0) { return false; } /* avoid div-by-zero */
   352→
   353→    double delta_pct;
   354→    if (ent->metric_type == RT_METRIC_LOSS)
   355→    {
   356→        /* increase in loss indicates drift */
   357→        delta_pct = ((current - baseline) / baseline) * 100.0;
   358→        return delta_pct >= ent->drift_threshold_pct;
   359→    }
   360→    else
   361→    {
   362→        /* decrease in metric (accuracy, F1, etc.) indicates drift */
   363→        delta_pct = ((baseline - current) / baseline) * 100.0;
   364→        return delta_pct >= ent->drift_threshold_pct;
   365→    }
   366→}
   367→
   368→void rt_check_and_schedule(void)
   369→{
   370→    if (!_rt_state.initialized || !_rt_state.callback) { return; }
   371→
   372→    pthread_mutex_lock(&_rt_state.mtx);
   373→
   374→    /* scan registry */
   375→    for (size_t i = 0; i < RT_MAX_MODELS; ++i)
   376→    {
   377→        rt_model_entry_t *ent = &_rt_state.entries[i];
   378→        if (!ent->in_use || ent->retrain_pending) { continue; }
   379→
   380→        if (_rt_drift_detected(ent))
   381→        {
   382→            ent->retrain_pending = true;
   383→            /* Unlock during callback to avoid deadlocks */
   384→            pthread_mutex_unlock(&_rt_state.mtx);
   385→            bool ok = _rt_state.callback(ent->model_id);
   386→            pthread_mutex_lock(&_rt_state.mtx);
   387→
   388→            if (ok)
   389→            {
   390→                /* Callback accepted the scheduling – reset samples to establish new baseline */
   391→                ent->count            = 0;
   392→                ent->head             = 0;
   393→                ent->retrain_pending  = false;
   394→            }
   395→            /* else: keep pending flag set for future retries */
   396→        }
   397→    }
   398→
   399→    pthread_mutex_unlock(&_rt_state.mtx);
   400→}
   401→
   402→bool rt_has_pending_retraining(const char *model_id)
   403→{
   404→    if (!model_id) { return false; }
   405→    bool pending = false;
   406→    pthread_mutex_lock(&_rt_state.mtx);
   407→    rt_model_entry_t *ent = _rt_find_entry(model_id);
   408→    if (ent) { pending = ent->retrain_pending; }
   409→    pthread_mutex_unlock(&_rt_state.mtx);
   410→    return pending;
   411→}
   412→
