    80→/* ------------------------------------------------------------------------- *
    81→ *                      Public API — constructor/destructor                   *
    82→ * ------------------------------------------------------------------------- */
    83→
    84→pipeline_manager_t *
    85→pipeline_manager_create(const char *pipeline_name,
