    31→/* ────────────────────────────────────────────────────────────────────────── */
    32→/*                               Logger                                      */
    33→/* ────────────────────────────────────────────────────────────────────────── */
    34→
    35→typedef enum
    36→{
    37→    LOG_DEBUG = 0,
    38→    LOG_INFO,
    39→    LOG_WARN,
    40→    LOG_ERROR
    41→} LogLevel;
    42→
    43→static const char *LOG_LEVEL_STR[] = { "DEBUG", "INFO", "WARN", "ERROR" };
    44→
    45→typedef struct
    46→{
    47→    LogLevel        level;
    48→    FILE           *sink;
    49→    pthread_mutex_t lock;
    50→} Logger;
    51→
    52→static Logger g_logger;
    53→
    54→static void logger_init(LogLevel level, const char *file_path)
    55→{
    56→    g_logger.level = level;
    57→    g_logger.sink  = file_path ? fopen(file_path, "a") : stderr;
    58→    if (!g_logger.sink)
    59→    {
    60→        /* Fallback to stderr if file cannot be opened */
    61→        g_logger.sink = stderr;
    62→    }
    63→    pthread_mutex_init(&g_logger.lock, NULL);
    64→}
    65→
    66→static void logger_shutdown(void)
    67→{
    68→    if (g_logger.sink && g_logger.sink != stderr && g_logger.sink != stdout)
    69→        fclose(g_logger.sink);
    70→    pthread_mutex_destroy(&g_logger.lock);
    71→}
    72→
    73→__attribute__((format(printf, 3, 4))) static void logger_log(LogLevel lvl,
    74→                                                             const char *file,
    75→                                                             const char *fmt,
    76→                                                             ...)
    77→{
    78→    if (lvl < g_logger.level)
    79→        return;
    80→
    81→    time_t     now = time(NULL);
    82→    struct tm  tm_now;
    83→    char       ts[32];
    84→
    85→    localtime_r(&now, &tm_now);
    86→    strftime(ts, sizeof ts, "%Y-%m-%d %H:%M:%S", &tm_now);
    87→
    88→    pthread_mutex_lock(&g_logger.lock);
    89→
    90→    fprintf(g_logger.sink, "%s [%s] (%s) ", ts, LOG_LEVEL_STR[lvl], file);
    91→
    92→    va_list ap;
    93→    va_start(ap, fmt);
    94→    vfprintf(g_logger.sink, fmt, ap);
    95→    va_end(ap);
    96→
    97→    fprintf(g_logger.sink, "\n");
    98→    fflush(g_logger.sink);
    99→
   100→    pthread_mutex_unlock(&g_logger.lock);
   101→}
   102→
   103→#define LOG_DEBUG(fmt, ...) logger_log(LOG_DEBUG, __FILE__, fmt, ##__VA_ARGS__)
   104→#define LOG_INFO(fmt, ...)  logger_log(LOG_INFO, __FILE__, fmt, ##__VA_ARGS__)
   105→#define LOG_WARN(fmt, ...)  logger_log(LOG_WARN, __FILE__, fmt, ##__VA_ARGS__)
   106→#define LOG_ERROR(fmt, ...) logger_log(LOG_ERROR, __FILE__, fmt, ##__VA_ARGS__)
