   108→/* ────────────────────────────────────────────────────────────────────────── */
   109→/*                             Configuration                                 */
   110→/* ────────────────────────────────────────────────────────────────────────── */
   111→
   112→typedef struct
   113→{
   114→    char lms_api_endpoint[256];
   115→    char feature_store_path[256];
   116→    int  retrain_interval_sec;
   117→    char registry_path[256];
   118→    char strategy[64];
   119→} Config;
   120→
   121→static bool parse_config_line(const char *line, char *key, size_t key_sz,
   122→                              char *val, size_t val_sz)
   123→{
   124→    const char *eq = strchr(line, '=');
   125→    if (!eq)
   126→        return false;
   127→    size_t klen = (size_t)(eq - line);
   128→    size_t vlen = strlen(eq + 1);
   129→
   130→    if (klen >= key_sz || vlen >= val_sz)
   131→        return false;
   132→
   133→    strncpy(key, line, klen);
   134→    key[klen] = '\0';
   135→    strncpy(val, eq + 1, vlen);
   136→    /* trim trailing newline */
   137→    if (val[vlen - 1] == '\n')
   138→        val[vlen - 1] = '\0';
   139→    return true;
   140→}
   141→
   142→static bool load_config(const char *path, Config *cfg)
   143→{
   144→    FILE *fp = fopen(path, "r");
   145→    if (!fp)
   146→    {
   147→        LOG_ERROR("Failed to open config file '%s': %s", path, strerror(errno));
   148→        return false;
   149→    }
   150→
   151→    /* Set sensible defaults */
   152→    memset(cfg, 0, sizeof *cfg);
   153→    strcpy(cfg->lms_api_endpoint, "https://api.example.edu/lms");
   154→    strcpy(cfg->feature_store_path, "/var/lib/lexilearn/features");
   155→    strcpy(cfg->registry_path, "/var/lib/lexilearn/registry");
   156→    cfg->retrain_interval_sec = 3600;
   157→    strcpy(cfg->strategy, "transformer");
   158→
   159→    char  line[512];
   160→    char  key[128], val[384];
   161→    while (fgets(line, sizeof line, fp))
   162→    {
   163→        if (line[0] == '#' || line[0] == '\n')
   164→            continue;
   165→        if (!parse_config_line(line, key, sizeof key, val, sizeof val))
   166→            continue;
   167→
   168→        if (strcmp(key, "lms_api_endpoint") == 0)
   169→            strncpy(cfg->lms_api_endpoint, val, sizeof cfg->lms_api_endpoint);
   170→        else if (strcmp(key, "feature_store_path") == 0)
   171→            strncpy(cfg->feature_store_path, val,
   172→                    sizeof cfg->feature_store_path);
   173→        else if (strcmp(key, "retrain_interval_sec") == 0)
   174→            cfg->retrain_interval_sec = atoi(val);
   175→        else if (strcmp(key, "registry_path") == 0)
   176→            strncpy(cfg->registry_path, val, sizeof cfg->registry_path);
   177→        else if (strcmp(key, "strategy") == 0)
   178→            strncpy(cfg->strategy, val, sizeof cfg->strategy);
   179→    }
   180→
   181→    fclose(fp);
   182→    return true;
   183→}
