   185→/* ────────────────────────────────────────────────────────────────────────── */
   186→/*                           Model Registry                                  */
   187→/* ────────────────────────────────────────────────────────────────────────── */
   188→
   189→typedef struct
   190→{
   191→    char   active_version[64];
   192→    size_t total_versions;
   193→    pthread_mutex_t lock;
   194→} ModelRegistry;
   195→
   196→static bool registry_init(ModelRegistry *reg, const char *path)
   197→{
   198→    (void)path; /* Persisted registry omitted in this self-contained example */
   199→    memset(reg, 0, sizeof *reg);
   200→    pthread_mutex_init(&reg->lock, NULL);
   201→    strcpy(reg->active_version, "none");
   202→    return true;
   203→}
   204→
   205→static void registry_shutdown(ModelRegistry *reg)
   206→{
   207→    pthread_mutex_destroy(&reg->lock);
   208→}
   209→
   210→static void registry_register(ModelRegistry *reg, const char *version_tag)
   211→{
   212→    pthread_mutex_lock(&reg->lock);
   213→    strncpy(reg->active_version, version_tag, sizeof reg->active_version);
   214→    ++reg->total_versions;
   215→    pthread_mutex_unlock(&reg->lock);
   216→
   217→    LOG_INFO("Registered new model version: %s (total=%zu)", version_tag,
   218→             reg->total_versions);
   219→}
   220→
   221→static void registry_get_active(ModelRegistry *reg, char *buf, size_t sz)
   222→{
   223→    pthread_mutex_lock(&reg->lock);
   224→    strncpy(buf, reg->active_version, sz);
   225→    pthread_mutex_unlock(&reg->lock);
   226→}
