   228→/* ────────────────────────────────────────────────────────────────────────── */
   229→/*                          Observer Framework                               */
   230→/* ────────────────────────────────────────────────────────────────────────── */
   231→
   232→typedef enum
   233→{
   234→    EVT_MODEL_DRIFT_DETECTED = 0,
   235→    EVT_RETRAIN_COMPLETE,
   236→    EVT_SHUTDOWN
   237→} EventType;
   238→
   239→typedef void (*observer_cb)(EventType evt, void *user_data);
   240→
   241→#define MAX_OBSERVERS 32
   242→typedef struct
   243→{
   244→    observer_cb  cb;
   245→    void        *user_data;
   246→} Observer;
   247→
   248→static Observer g_observers[MAX_OBSERVERS];
   249→static size_t   g_observer_cnt = 0;
   250→
   251→static bool observer_register(observer_cb cb, void *user_data)
   252→{
   253→    if (g_observer_cnt >= MAX_OBSERVERS)
   254→        return false;
   255→    g_observers[g_observer_cnt++] = (Observer){ .cb = cb,
   256→                                                .user_data = user_data };
   257→    return true;
   258→}
   259→
   260→static void observer_notify(EventType evt)
   261→{
   262→    for (size_t i = 0; i < g_observer_cnt; ++i)
   263→        g_observers[i].cb(evt, g_observers[i].user_data);
   264→}
