   266→/* ────────────────────────────────────────────────────────────────────────── */
   267→/*                          Strategy Pattern                                 */
   268→/* ────────────────────────────────────────────────────────────────────────── */
   269→
   270→typedef struct
   271→{
   272→    const char *name;
   273→    /* placeholder for strategy-specific state */
   274→    int (*train)(const Config *cfg, const char *dataset_path,
   275→                 char *out_version, size_t out_sz);
   276→    int (*inference)(const char *input, char *output, size_t out_sz);
   277→} ModelStrategy;
   278→
   279→/* transformer strategy */
   280→static int transformer_train(const Config *cfg, const char *dataset_path,
   281→                             char *out_version, size_t out_sz)
   282→{
   283→    (void)cfg;
   284→    (void)dataset_path;
   285→    /* In real life we would call Python or ONNX Runtime; here we simulate. */
   286→    snprintf(out_version, out_sz, "transformer-%ld", time(NULL));
   287→    sleep(2); /* pretend it takes some time */
   288→    LOG_INFO("[Strategy:transformer] training complete, version=%s",
   289→             out_version);
   290→    return 0;
   291→}
   292→
   293→static int transformer_inference(const char *input, char *output, size_t sz)
   294→{
   295→    snprintf(output, sz, "[transformer] summary of '%s'", input);
   296→    return 0;
   297→}
   298→
   299→/* n-gram strategy – simplified */
   300→static int ngram_train(const Config *cfg, const char *dataset_path,
   301→                       char *out_version, size_t out_sz)
   302→{
   303→    (void)cfg;
   304→    (void)dataset_path;
   305→    snprintf(out_version, out_sz, "ngram-%ld", time(NULL));
   306→    sleep(1);
   307→    LOG_INFO("[Strategy:ngram] training complete, version=%s", out_version);
   308→    return 0;
   309→}
   310→
   311→static int ngram_inference(const char *input, char *output, size_t sz)
   312→{
   313→    snprintf(output, sz, "[ngram] summary of '%s'", input);
   314→    return 0;
   315→}
   316→
   317→static const ModelStrategy STRATEGIES[] = {
   318→    { .name = "transformer",
   319→      .train = transformer_train,
   320→      .inference = transformer_inference },
   321→    { .name = "ngram",
   322→      .train = ngram_train,
   323→      .inference = ngram_inference },
   324→};
   325→
   326→static const ModelStrategy *strategy_from_name(const char *name)
   327→{
   328→    for (size_t i = 0; i < sizeof STRATEGIES / sizeof STRATEGIES[0]; ++i)
   329→        if (strcmp(name, STRATEGIES[i].name) == 0)
   330→            return &STRATEGIES[i];
   331→    return NULL;
   332→}
