   334→/* ────────────────────────────────────────────────────────────────────────── */
   335→/*                          Controller – Pipeline                            */
   336→/* ────────────────────────────────────────────────────────────────────────── */
   337→
   338→typedef struct
   339→{
   340→    const Config          *cfg;
   341→    ModelRegistry         *registry;
   342→    const ModelStrategy   *strategy;
   343→} PipelineCtx;
   344→
   345→static bool ingest_data(const Config *cfg, char *dataset_path, size_t sz)
   346→{
   347→    /* Pretend to download data from LMS API */
   348→    (void)cfg;
   349→    snprintf(dataset_path, sz, "/tmp/lexilearn_dataset_%ld.csv", time(NULL));
   350→    LOG_INFO("Ingested LMS data to %s", dataset_path);
   351→    return true;
   352→}
   353→
   354→static bool evaluate_model(const char *version_tag)
   355→{
   356→    (void)version_tag;
   357→    /* placeholder */
   358→    LOG_INFO("Evaluated model %s – metrics within thresholds", version_tag);
   359→    return true;
   360→}
   361→
   362→static void *pipeline_run(void *arg)
   363→{
   364→    PipelineCtx *ctx = arg;
   365→
   366→    char dataset_path[256];
   367→    if (!ingest_data(ctx->cfg, dataset_path, sizeof dataset_path))
   368→    {
   369→        LOG_ERROR("Data ingestion failed. Aborting pipeline.");
   370→        return NULL;
   371→    }
   372→
   373→    char new_version[64];
   374→    if (ctx->strategy->train(ctx->cfg, dataset_path, new_version,
   375→                             sizeof new_version) != 0)
   376→    {
   377→        LOG_ERROR("Training failed.");
   378→        return NULL;
   379→    }
   380→
   381→    if (!evaluate_model(new_version))
   382→    {
   383→        LOG_WARN("Model %s fails eval; not promoting.", new_version);
   384→        return NULL;
   385→    }
   386→
   387→    registry_register(ctx->registry, new_version);
   388→
   389→    observer_notify(EVT_RETRAIN_COMPLETE);
   390→    return NULL;
   391→}
