   393→/* ────────────────────────────────────────────────────────────────────────── */
   394→/*                      Scheduler / Model-Drift Monitor                      */
   395→/* ────────────────────────────────────────────────────────────────────────── */
   396→
   397→typedef struct
   398→{
   399→    const Config  *cfg;
   400→    PipelineCtx   *pipeline;
   401→    pthread_t      thread;
   402→    bool           running;
   403→} Scheduler;
   404→
   405→static void *scheduler_loop(void *arg)
   406→{
   407→    Scheduler *sch = arg;
   408→    LOG_INFO("Scheduler started; retrain interval = %d seconds",
   409→             sch->cfg->retrain_interval_sec);
   410→
   411→    while (sch->running)
   412→    {
   413→        sleep(sch->cfg->retrain_interval_sec);
   414→
   415→        /* Simulate model drift detection */
   416→        bool drift = (rand() % 100) < 30; /* 30% chance */
   417→        if (drift)
   418→        {
   419→            LOG_WARN("Model drift detected!");
   420→            observer_notify(EVT_MODEL_DRIFT_DETECTED);
   421→
   422→            pthread_t worker;
   423→            pthread_create(&worker, NULL, pipeline_run, sch->pipeline);
   424→            pthread_detach(worker);
   425→        }
   426→    }
   427→    return NULL;
   428→}
   429→
   430→static bool scheduler_start(Scheduler *sch)
   431→{
   432→    sch->running = true;
   433→    if (pthread_create(&sch->thread, NULL, scheduler_loop, sch) != 0)
   434→        return false;
   435→    return true;
   436→}
   437→
   438→static void scheduler_stop(Scheduler *sch)
   439→{
   440→    sch->running = false;
   441→    pthread_join(sch->thread, NULL);
   442→}
