   444→/* ────────────────────────────────────────────────────────────────────────── */
   445→/*                        Global Shutdown Handling                            */
   446→/* ────────────────────────────────────────────────────────────────────────── */
   447→
   448→static volatile sig_atomic_t g_shutdown_requested = 0;
   449→
   450→static void sig_handler(int sig)
   451→{
   452→    (void)sig;
   453→    g_shutdown_requested = 1;
   454→    observer_notify(EVT_SHUTDOWN);
   455→}
   456→
   457→/* Observer callback to log events */
   458→static void event_logger(EventType evt, void *ud)
   459→{
   460→    (void)ud;
   461→    switch (evt)
   462→    {
   463→        case EVT_MODEL_DRIFT_DETECTED:
   464→            LOG_INFO("[Observer] Model drift detected – pipeline triggered");
   465→            break;
   466→        case EVT_RETRAIN_COMPLETE:
   467→            LOG_INFO("[Observer] Retraining job complete");
   468→            break;
   469→        case EVT_SHUTDOWN:
   470→            LOG_INFO("[Observer] Shutdown signal received");
   471→            break;
   472→        default:
   473→            break;
   474→    }
   475→}
