   477→/* ────────────────────────────────────────────────────────────────────────── */
   478→/*                                main                                        */
   479→/* ────────────────────────────────────────────────────────────────────────── */
   480→
   481→static void usage(const char *prog)
   482→{
   483→    fprintf(stderr, "Usage: %s [-c config.ini] [-l loglevel]\n", prog);
   484→    fprintf(stderr, "   loglevel: DEBUG, INFO, WARN, ERROR (default INFO)\n");
   485→}
   486→
   487→static LogLevel parse_level(const char *s)
   488→{
   489→    if (strcasecmp(s, "DEBUG") == 0)
   490→        return LOG_DEBUG;
   491→    if (strcasecmp(s, "INFO") == 0)
   492→        return LOG_INFO;
   493→    if (strcasecmp(s, "WARN") == 0)
   494→        return LOG_WARN;
   495→    if (strcasecmp(s, "ERROR") == 0)
   496→        return LOG_ERROR;
   497→    return LOG_INFO;
   498→}
   499→
   500→int main(int argc, char **argv)
   501→{
   502→    const char *cfg_path  = "lexilearn.ini";
   503→    LogLevel    log_level = LOG_INFO;
   504→
   505→    int opt;
   506→    while ((opt = getopt(argc, argv, "c:l:h")) != -1)
   507→    {
   508→        switch (opt)
   509→        {
   510→            case 'c':
   511→                cfg_path = optarg;
   512→                break;
   513→            case 'l':
   514→                log_level = parse_level(optarg);
   515→                break;
   516→            case 'h':
   517→            default:
   518→                usage(argv[0]);
   519→                return EXIT_FAILURE;
   520→        }
   521→    }
   522→
   523→    logger_init(log_level, NULL);
   524→    LOG_INFO("LexiLearn Orchestrator starting…");
   525→
   526→    /* Register signal handlers for graceful shutdown */
   527→    struct sigaction sa;
   528→    memset(&sa, 0, sizeof sa);
   529→    sa.sa_handler = sig_handler;
   530→    sigaction(SIGINT, &sa, NULL);
   531→    sigaction(SIGTERM, &sa, NULL);
   532→
   533→    Config cfg;
   534→    if (!load_config(cfg_path, &cfg))
   535→    {
   536→        LOG_ERROR("Unable to load configuration.");
   537→        logger_shutdown();
   538→        return EXIT_FAILURE;
   539→    }
   540→
   541→    const ModelStrategy *strategy = strategy_from_name(cfg.strategy);
   542→    if (!strategy)
   543→    {
   544→        LOG_ERROR("Unknown strategy '%s'", cfg.strategy);
   545→        logger_shutdown();
   546→        return EXIT_FAILURE;
   547→    }
   548→    LOG_INFO("Using strategy: %s", strategy->name);
   549→
   550→    ModelRegistry registry;
   551→    if (!registry_init(&registry, cfg.registry_path))
   552→    {
   553→        LOG_ERROR("Failed to initialise model registry.");
   554→        logger_shutdown();
   555→        return EXIT_FAILURE;
   556→    }
   557→
   558→    if (!observer_register(event_logger, NULL))
   559→    {
   560→        LOG_WARN("Could not register event logger observer");
   561→    }
   562→
   563→    PipelineCtx pipeline_ctx = { .cfg = &cfg,
   564→                                 .registry = &registry,
   565→                                 .strategy = strategy };
   566→
   567→    Scheduler scheduler = { .cfg = &cfg, .pipeline = &pipeline_ctx };
   568→    if (!scheduler_start(&scheduler))
   569→    {
   570→        LOG_ERROR("Failed to start scheduler.");
   571→        registry_shutdown(&registry);
   572→        logger_shutdown();
   573→        return EXIT_FAILURE;
   574→    }
   575→
   576→    /* Main loop simply waits for shutdown signal */
   577→    while (!g_shutdown_requested)
   578→        pause();
   579→
   580→    LOG_INFO("Shutting down…");
   581→    scheduler_stop(&scheduler);
   582→    registry_shutdown(&registry);
   583→    logger_shutdown();
   584→    return EXIT_SUCCESS;
   585→}
