**Pipeline Manager calling Job Factory** (`pipeline_manager.c`, lines 296-338):
```c
static bool trigger_training_locked(pipeline_manager_t *pmgr, const char *reason) {
    // Build the Training Job via Factory Pattern
    training_job_t *job = training_job_factory_create(pmgr->job_factory, reason);

    if (!job) {
        LOG_ERROR("training_job_factory_create failed");
        return false;
    }

    // Register experiment with Model Registry
    char exp_id[MODEL_REGISTRY_MAX_ID];
    if (model_registry_create_experiment(pmgr->registry, job, reason, exp_id, sizeof(exp_id)) < 0) {
        LOG_ERROR("Failed to log experiment into Model Registry");
        training_job_destroy(job);
        return false;
    }

    LOG_INFO("Experiment '%s' registered, launching training job", exp_id);

    // Execute the training job
    if (training_job_execute(job) != 0) {
        LOG_ERROR("Training job execution failed for experiment '%s'", exp_id);
        model_registry_update_status(pmgr->registry, exp_id, MODEL_STATUS_FAILED);
        training_job_destroy(job);
        return false;
    }

    // Persist success status to registry
    model_registry_update_status(pmgr->registry, exp_id, MODEL_STATUS_SUCCEEDED);
    LOG_INFO("Training completed successfully for experiment '%s'", exp_id);
    training_job_destroy(job);
    return true;
}
```

